const profiles = $('Split Into Individual Profiles').all();

const sheetRows = $('Read Emails from Google Sheet').all().map(i => i.json);

function normalizeUrl(url) {
  return (url || '')
    .toLowerCase()
    .replace('www.', '')
    .trim();
}

const emailMap = {};

for (const row of sheetRows) {

  const urlKey = Object.keys(row).find(k =>
    k.toLowerCase().includes('profile') &&
    k.toLowerCase().includes('url')
  );

  const emailKey = Object.keys(row).find(k =>
    k.toLowerCase().includes('email') &&
    !k.toLowerCase().includes('status')   // 🚨 IMPORTANT
  );

  const url = normalizeUrl(urlKey ? row[urlKey] : '');
  const email = (emailKey ? row[emailKey] : '').trim();

  if (url && email && email.includes('@') && !email.toLowerCase().includes('restricted')) {
    emailMap[url] = email;
  }
}

const results = [];

for (const item of profiles) {

  const p = { ...item.json };

  if (!p.linkedin_url && !p.url) {
    console.log("Skipping non-profile item:", p);
    continue;
  }

  const currentEmail = (p.email || '').toLowerCase();

  const isInvalid =
    !currentEmail ||
    !currentEmail.includes('@') ||
    currentEmail.includes('restricted');

  if (isInvalid) {
    const url = normalizeUrl(p.url || p.linkedin_url || '');
    const sheetEmail = emailMap[url];

    if (sheetEmail) {
      p.email = sheetEmail;
      p.email_source = 'google_sheet';
    }
  }

  const finalEmail = (p.email || '').trim();

  if (!finalEmail.includes('@')) continue;
  if (finalEmail.toLowerCase().includes('restricted')) continue;

  const status = (p["Email Status"] || p.status || '').toUpperCase();

  if (status === 'STOPPED' || status === 'REPLIED') continue;

  results.push({ json: p });
}

if (results.length === 0) {
  console.log("⚠️ No valid leads found — returning empty but safe output");
  return [];
}

return results;

const existingLeads = $input.all().map(i => i.json);
const flat = Array.isArray(existingLeads[0]) ? existingLeads[0] : existingLeads;
const existingEmails = new Set(flat.map(l => (l.email || '').toLowerCase()));
const existingUrls = new Set(flat.map(l => (l.linkedin_url || l.url || '').toLowerCase()));

// Get scraped profiles from the EARLIER node (not $input)
const currentItems = $('Fill Missing Emails from Sheet').all();
const results = [];

for (const item of currentItems) {
  console.log(item)
  const email = (item.json.email || '').toLowerCase();
  const url = (item.json.url || '').toLowerCase();
  const status = (item.json.status || 'NEW').toUpperCase();
  const isNew = !existingEmails.has(email) && !existingUrls.has(url);
  const isIgnored = status === 'IGNORED';
  const isNewStatus = status === 'NEW' || status === 'ACTIVE';
  if (isNew || isIgnored || isNewStatus) {
    results.push(item);
  }
}
return results;

